/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // The problem asks for the minimum cost to buy apples at store i,
    // which is min(prices[i], min_{j} (Travel_Cost(i->j, empty) + prices[j] + Travel_Cost(j->i, full))).
    // Since the roads are bidirectional, Travel_Cost(i->j, empty) = Travel_Cost(j->i, empty).
    // And Travel_Cost(j->i, full) = Travel_Cost(i->j, full).

    // Let D_empty[u][v] be the minimum cost to travel from u to v without apples.
    // Let D_full[u][v] be the minimum cost to travel from u to v with apples.

    // We need two sets of all-pairs shortest paths (APSP) or single-source shortest paths (SSSP)
    // from all nodes. Since N is small (<= 1000), Floyd-Warshall or running Dijkstra N times is feasible.
    // Given the structure, Dijkstra is usually preferred if the graph is sparse, but N=1000 suggests O(N^3) might be too slow,
    // O(N * (E + N log N)) is better. E <= 2000.

    // --- 1. Setup Adjacency Lists ---
    const adj_empty = Array(n).fill(0).map(() => []);
    const adj_full = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Empty travel cost: cost
        // Full travel cost: cost * tax

        // Bidirectional for both types of travel
        adj_empty[u].push({ to: v, weight: cost });
        adj_empty[v].push({ to: u, weight: cost });

        adj_full[u].push({ to: v, weight: cost * tax });
        adj_full[v].push({ to: u, weight: cost * tax });
    }

    // --- 2. Dijkstra's Algorithm Implementation ---
    // Function to run Dijkstra from a source node using a given adjacency list
    const dijkstra = (startNode, adj) => {
        const dist = Array(n).fill(Infinity);
        dist[startNode] = 0;

        // Min-Heap: [distance, node]
        const pq = [[0, startNode]]; 

        while (pq.length > 0) {
            // Simple sort simulation for priority queue (since JS doesn't have native heap)
            // For N=1000, this simulation might be slow, but let's use it for simplicity first.
            // A proper binary heap implementation would be better for competitive programming.
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > dist[u]) {
                continue;
            }

            for (const edge of adj[u]) {
                const v = edge.to;
                const weight = edge.weight;
                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.push([dist[v], v]);
                }
            }
        }
        return dist;
    };

    // --- 3. Compute Shortest Paths ---
    // D_empty[i] stores the distances from source i (empty travel)
    const D_empty = [];
    for (let i = 0; i < n; i++) {
        D_empty.push(dijkstra(i, adj_empty));
    }

    // D_full[i] stores the distances from source i (full travel)
    const D_full = [];
    for (let i = 0; i < n; i++) {
        D_full.push(dijkstra(i, adj_full));
    }


    // --- 4. Calculate Final Answer ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let min_cost = prices[i];

        // Option 2: Travel to j, buy, travel back to i
        // Cost = Travel_Empty(i -> j) + prices[j] + Travel_Full(j -> i)

        // Travel_Empty(i -> j) = D_empty[i][j]
        // Travel_Full(j -> i) = D_full[j][i] (Note the indices: start at j with apples, end at i)

        for (let j = 0; j < n; j++) {
            if (i === j) continue; // Covered by Option 1, but safe to include if we use general formula

            const travel_i_to_j_empty = D_empty[i][j];
            const travel_j_to_i_full = D_full[j][i];

            if (travel_i_to_j_empty !== Infinity && travel_j_to_i_full !== Infinity) {
                // Total cost = Empty trip cost (i->j) + Price at j + Full trip cost (j->i)
                const current_total_cost = travel_i_to_j_empty + prices[j] + travel_j_to_i_full;
                min_cost = Math.min(min_cost, current_total_cost);
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}

